import React from "react";
import "./certified.css";

const sliders = [
  {
    id: 1,
    title: "Enterprise Ready",
    paragraph: "SOC 2 Compliant",
  },
  {
    id: 2,
    title: "FinOps Certified",
    paragraph: "Best Practices",
  },
  {
    id: 3,
    title: "Bank-Grade Security",
    paragraph: "256-bit Encryption",
  },
  {
    id: 4,
    title: "Fast Deployment",
    paragraph: "Live in 48 hours",
  },
];
const Certified = () => {
  return (
    <>
      <div>
        <h6 className="headin">TRUSTED BY CLOUD-NATIVE ENTERPRISES</h6>
        <div className="card-wrapper">
          {sliders.map((slider) => (
            <div className="card" key={slider.id}>
              <h4>{slider.title}</h4>
              <p>{slider.paragraph}</p>
            </div>
          ))}
        </div>
      </div>
    </>
  );
};

export default Certified;
